// Event types
interface Event {
  id: string;
  aggregateId: string;
  timestamp: Date;
  type: string;
  data: unknown;
}

interface DepositEvent extends Event {
  type: 'Deposit';
  data: {
    amount: number;
  };
}

interface WithdrawEvent extends Event {
  type: 'Withdraw';
  data: {
    amount: number;
  };
}

interface TransferEvent extends Event {
  type: 'Transfer';
  data: {
    amount: number;
    fromAccountId: string;
    toAccountId: string;
  };
}

// Account class (aggregate)
class Account {
  private id: string;
  private balance: number = 0;
  private events: Event[] = [];

  constructor(id: string) {
    this.id = id;
  }

  deposit(amount: number): void {
    if (amount <= 0) {
      throw new Error('Deposit amount must be positive');
    }

    const event: DepositEvent = {
      id: this.generateEventId(),
      aggregateId: this.id,
      timestamp: new Date(),
      type: 'Deposit',
      data: { amount }
    };

    this.apply(event);
    this.events.push(event);
  }

  withdraw(amount: number): void {
    if (amount <= 0) {
      throw new Error('Withdrawal amount must be positive');
    }

    if (this.balance < amount) {
      throw new Error('Insufficient funds');
    }

    const event: WithdrawEvent = {
      id: this.generateEventId(),
      aggregateId: this.id,
      timestamp: new Date(),
      type: 'Withdraw',
      data: { amount }
    };

    this.apply(event);
    this.events.push(event);
  }

  private apply(event: Event): void {
    switch (event.type) {
      case 'Deposit':
        this.balance += (event as DepositEvent).data.amount;
        break;
      case 'Withdraw':
        this.balance -= (event as WithdrawEvent).data.amount;
        break;
      case 'Transfer':
        const transferData = (event as TransferEvent).data;
        if (event.aggregateId === this.id && transferData.fromAccountId === this.id) {
          this.balance -= transferData.amount;
        } else if (transferData.toAccountId === this.id) {
          this.balance += transferData.amount;
        }
        break;
    }
  }

  getBalance(): number {
    return this.balance;
  }

  getEvents(): Event[] {
    return [...this.events];
  }

  loadFromHistory(events: Event[]): void {
    this.events = [];
    this.balance = 0;
    events.forEach(event => this.apply(event));
    this.events = events;
  }

  private generateEventId(): string {
    return `${this.id}-${Date.now()}-${Math.random()}`;
  }
}

export { Account, Event, DepositEvent, WithdrawEvent, TransferEvent };
```

This implementation covers the core event sourcing pattern with validation for deposits and withdrawals, an apply method to update state based on events, and the ability to reconstruct the account state from a history of events.

